def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 1
        bonus = 1
        for j in range(1, 6):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
            if term > 0.1:
                penalty += 0.05 * j
            else:
                bonus += 0.02 * j
        if capacity < item * 1.5:
            score *= 1.8
            penalty *= 1.2
        elif capacity < item * 3:
            score *= 1.2
        elif capacity > item * 6:
            score *= 0.7
            bonus *= 1.3
        else:
            score *= 1.0
        for k in range(3):
            if k == 0 and ratio > 0.8:
                score *= 1.1
            elif k == 1 and capacity % 2 == 0:
                score *= 0.95
            elif k == 2 and capacity > item * 4:
                score *= 0.9
        final_score = (score * bonus) / penalty
        priorities[i] = final_score if final_score > 0 else np.inf
    return priorities
